content:
{
  "sentences": [
    {
      "text": "今天天氣很熱，我可以喝一杯冰水嗎？",
      "pinyin": "Jīntiān tiānqì hěn rè, wǒ kěyǐ hē yī bēi bīng shuǐ ma?",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 re4, wo3 ke3yi3 he1 yi1 bei1 bing1 shui3 ma0",
      "translation_en": "It's very hot today, can I drink a glass of ice water?",
      "translation_ko": "오늘 날씨가 매우 더운데, 얼음 물 한 잔 마셔도 될까요?"
    },
    {
      "text": "請問，我可以先看菜單再點餐嗎？",
      "pinyin": "Qǐngwèn, wǒ kěyǐ xiān kàn càidān zài diǎncān ma?",
      "pinyin_numeric": "qing3wen4, wo3 ke3yi3 xian1 kan4 cai4dan1 zai4 dian3can1 ma0",
      "translation_en": "Excuse me, can I look at the menu first before ordering?",
      "translation_ko": "실례합니다, 먼저 메뉴를 보고 주문해도 될까요?"
    },
    {
      "text": "外面下雨了，我可以跟你一起撐傘嗎？",
      "pinyin": "Wàimiàn xiàyǔ le, wǒ kěyǐ gēn nǐ yīqǐ chēng sǎn ma?",
      "pinyin_numeric": "wai4mian4 xia4yu3 le0, wo3 ke3yi3 gen1 ni3 yi1qi3 cheng1 san3 ma0",
      "translation_en": "It's raining outside, can I share an umbrella with you?",
      "translation_ko": "밖에 비가 오는데, 당신과 함께 우산을 써도 될까요?"
    },
    {
      "text": "我心情不好，你可以陪我散步一下嗎？",
      "pinyin": "Wǒ xīnqíng bù hǎo, nǐ kěyǐ péi wǒ sànbù yīxià ma?",
      "pinyin_numeric": "wo3 xin1qing2 bu4 hao3, ni3 ke3yi3 pei2 wo3 san4bu4 yi1xia4 ma0",
      "translation_en": "I'm in a bad mood, can you take a walk with me for a bit?",
      "translation_ko": "기분이 안 좋은데, 저랑 잠시 산책해 주실 수 있나요?"
    },
    {
      "text": "這件外套太大了，我可以試穿小號的嗎？",
      "pinyin": "Zhè jiàn wàitào tài dà le, wǒ kěyǐ shìchuān xiǎo hào de ma?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 tai4 da4 le0, wo3 ke3yi3 shi4chuan1 xiao3 hao4 de0 ma0",
      "translation_en": "This jacket is too big, can I try on a small size?",
      "translation_ko": "이 외투가 너무 큰데, 작은 사이즈를 입어 봐도 될까요?"
    },
    {
      "text": "颱風要來了，我們可以先回家嗎？",
      "pinyin": "Táifēng yào lái le, wǒmen kěyǐ xiān huí jiā ma?",
      "pinyin_numeric": "tai2feng1 yao4 lai2 le0, wo3men ke3yi3 xian1 hui2 jia1 ma0",
      "translation_en": "A typhoon is coming, can we go home first?",
      "translation_ko": "태풍이 오려고 하는데, 우리 먼저 집에 가도 될까요?"
    },
    {
      "text": "我壓力很大，可以放鬆一下聽音樂嗎？",
      "pinyin": "Wǒ yālì hěn dà, kěyǐ fàngsōng yīxià tīng yīnyuè ma?",
      "pinyin_numeric": "wo3 ya1li4 hen3 da4, ke3yi3 fang4song1 yi1xia4 ting1 yin1yue4 ma0",
      "translation_en": "I'm under a lot of pressure, can I relax and listen to music?",
      "translation_ko": "스트레스가 많은데, 잠시 긴장 풀고 음악을 들어도 될까요?"
    },
    {
      "text": "路很滑，你可以走慢一點嗎？",
      "pinyin": "Lù hěn huá, nǐ kěyǐ zǒu màn yīdiǎn ma?",
      "pinyin_numeric": "lu4 hen3 hua2, ni3 ke3yi3 zou3 man4 yi1dian3 ma0",
      "translation_en": "The road is very slippery, can you walk a bit slower?",
      "translation_ko": "길이 미끄러운데, 조금 천천히 걸어 주실 수 있나요?"
    },
    {
      "text": "我沒有帶傘，可以跟你借一把嗎？",
      "pinyin": "Wǒ méiyǒu dài sǎn, kěyǐ gēn nǐ jiè yī bǎ ma?",
      "pinyin_numeric": "wo3 mei2you3 dai4 san3, ke3yi3 gen1 ni3 jie4 yi1 ba3 ma0",
      "translation_en": "I didn't bring an umbrella, can I borrow one from you?",
      "translation_ko": "우산을 안 가져왔는데, 당신 것 하나 빌려도 될까요?"
    },
    {
      "text": "天氣很冷，我可以穿你的外套嗎？",
      "pinyin": "Tiānqì hěn lěng, wǒ kěyǐ chuān nǐ de wàitào ma?",
      "pinyin_numeric": "tian1qi4 hen3 leng3, wo3 ke3yi3 chuan1 ni3 de0 wai4tao4 ma0",
      "translation_en": "It's very cold, can I wear your jacket?",
      "translation_ko": "날씨가 매우 추운데, 당신 외투를 입어도 될까요?"
    }
  ]
}
